async (params, browser) => {
  // Open title page
  await browser.open(`${params.title_url}`)

  // Wait for title page
  await browser.waitForSelector('[data-testid=\'hero-title-block__title\'], h1, [class*=\'TitleHeader\']', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll to load content
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract title details
  const title_data = await browser.evaluate(`const titleEl = document.querySelector('[data-testid="hero-title-block__title"], h1[data-testid], h1'); const yearEl = document.querySelector('[data-testid="hero-title-block__metadata"] a[href*="releaseinfo"], [data-testid="hero-title-block__metadata"] li a, ul[data-testid] li a[href*="releaseinfo"]'); const ratingEl = document.querySelector('[data-testid="hero-rating-bar__aggregate-rating__score"] span, .ipc-rating-star--rating, [class*="AggregateRatingButton"] span'); const voteCountEl = document.querySelector('[data-testid="hero-rating-bar__aggregate-rating__score"] + div + div, [class*="rating-count"]'); const plotEl = document.querySelector('[data-testid="plot-xl"], [data-testid="plot"] span, span[data-testid="plot-xl"]'); const genres = []; document.querySelectorAll('[data-testid="genres"] a, div[data-testid="genres"] .ipc-chip__text').forEach(function(el) { genres.push(el.textContent.trim()); }); const runtimeEl = document.querySelector('[data-testid="title-techspec_runtime"] li, [data-testid="title-techspec_runtime"] .ipc-metadata-list-item__content-container'); const directorEls = document.querySelectorAll('[data-testid="title-pc-principal-credit"] a[href*="/name/"]'); const director = directorEls.length > 0 ? directorEls[0].textContent.trim() : ''; const cast = []; document.querySelectorAll('[data-testid="title-cast-item"]').forEach(function(el) { const nameEl = el.querySelector('[data-testid="title-cast-item__actor"], a[href*="/name/"]'); const charEl = el.querySelector('[data-testid="cast-item-characters-link"], [class*="character"]'); const imgEl = el.querySelector('img'); cast.push({ name: nameEl ? nameEl.textContent.trim() : '', character: charEl ? charEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '' }); }); const posterEl = document.querySelector('[data-testid="hero-media__poster"] img, img.ipc-image'); const metascoreEl = document.querySelector('[class*="metacritic"], [data-testid="metacritic-score-box"]'); return { title: titleEl ? titleEl.textContent.trim() : '', year: yearEl ? yearEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', vote_count: voteCountEl ? voteCountEl.textContent.trim() : '', plot: plotEl ? plotEl.textContent.trim().substring(0, 1000) : '', genres: genres, runtime: runtimeEl ? runtimeEl.textContent.trim() : '', director: director, cast: cast.slice(0, 15), poster: posterEl ? posterEl.getAttribute('src') : '', metascore: metascoreEl ? metascoreEl.textContent.trim() : '', url: window.location.href }`)

  return title_data
}
